TargetContent:
let statusKey = 'published';
if (!item.visible) statusKey = 'draft';
else if (item.openForSubmissions === false) statusKey = 'closed';
else if (item.dueAt && new Date(item.dueAt) < new Date()) statusKey = 'late';

if (filterStatus !== 'all' && statusKey !== filterStatus) return false;
return true;
